FUNCTION CalculateCPUCores(requestsPerSec, cpuTimeMs, safetyFactor)
 // Input validation
 IF requestsPerSec <= 0 OR cpuTimeMs <= 0 THEN
 RETURN "Invalid input values"
 ENDIF

 // Convert ms to seconds
 cpuTimeSec = cpuTimeMs / 1000

 // Calculate CPU utilization per second
 cpuRequired = requestsPerSec * cpuTimeSec

 // Apply safety factor
 cpuWithBuffer = cpuRequired * safetyFactor

 // Round up to whole cores
 coresNeeded = CEILING(cpuWithBuffer)

 // Output results
 PRINT "Base CPU requirement: " + cpuRequired + " cores"
 PRINT "With safety factor " + safetyFactor + ": " + coresNeeded + " cores"

 RETURN coresNeeded
END FUNCTION

// Example: 500 req/sec, 20ms CPU time, 1.5 safety factor
// Result: 15 cores

FUNCTION CalculateResponseTime(serviceTimeMs, utilizationPercent)
 // Input validation
 IF utilizationPercent >= 100 THEN
 PRINT "WARNING: System overloaded at 100% utilization"
 RETURN "Infinite wait time"
 ENDIF

 // Convert percentage to decimal
 utilization = utilizationPercent / 100

 // Calculate wait time using queuing formula
 // Wait_Time = Service_Time * (Utilization / (1 - Utilization))
 waitTimeMs = serviceTimeMs * (utilization / (1 - utilization))

 // Total response time
 totalResponseTimeMs = serviceTimeMs + waitTimeMs

 // Output results
 PRINT "Service Time: " + serviceTimeMs + " ms"
 PRINT "Wait Time: " + ROUND(waitTimeMs, 2) + " ms"
 PRINT "Total Response Time: " + ROUND(totalResponseTimeMs, 2) + " ms"
 PRINT "Utilization: " + utilizationPercent + "%"

 // Warning for high utilization
 IF utilizationPercent > 80 THEN
 PRINT "WARNING: Response time degrading rapidly!"
 ENDIF

 RETURN totalResponseTimeMs
END FUNCTION

