FUNCTION EstimateStorage(baseDataTB, numUsers, dataPerUserGB, growthRate, years, compressionRatio)
 // Convert all to consistent units (TB)
 dataPerUserTB = dataPerUserGB / 1000

 // Calculate initial storage requirement
 initialStorage = numUsers * dataPerUserTB

 // Apply growth rate for each year
 // Compound growth: Final = Initial * (1 + rate)^years
 storageWithGrowth = initialStorage * POWER((1 + growthRate), years)

 // Apply compression ratio (compressed = raw / ratio)
 compressedStorage = storageWithGrowth / compressionRatio

 // Add base data
 totalStorage = compressedStorage + baseDataTB

 // Add capacity buffer (30%)
 totalWithBuffer = totalStorage * 1.30

 // Output
 PRINT "Initial storage: " + ROUND(initialStorage, 2) + " TB"
 PRINT "After " + years + " years growth: " + ROUND(storageWithGrowth, 2) + " TB"
 PRINT "After " + compressionRatio + ":1 compression: " + ROUND(compressedStorage, 2) + " TB"
 PRINT "With 30% buffer: " + ROUND(totalWithBuffer, 2) + " TB"

 RETURN ROUND(totalWithBuffer, 2)
END FUNCTION

